-- Kết thúc file dữ liệu mẫu
-- Realistic seed data for clinic management system (MySQL 8+)
-- Notes:
-- 1) UUID columns generated by JPA are typically BINARY(16) on MySQL with Hibernate.
--    This script uses UUID_TO_BIN for those columns.
-- 2) Insert order follows FK dependencies.
-- 3) Role table has exactly 3 values: ADMIN, DOCTOR, PATIENT.

SET FOREIGN_KEY_CHECKS = 0;

TRUNCATE TABLE user_role;
TRUNCATE TABLE admin;
TRUNCATE TABLE doctor_certificate;
TRUNCATE TABLE review;
TRUNCATE TABLE medical_record;
TRUNCATE TABLE prescription_detail;
TRUNCATE TABLE prescription;
TRUNCATE TABLE appointment;
TRUNCATE TABLE schedule;
TRUNCATE TABLE doctor;
TRUNCATE TABLE patient;
TRUNCATE TABLE users;
TRUNCATE TABLE role;
TRUNCATE TABLE specialty;
TRUNCATE TABLE payments;
TRUNCATE TABLE banners;
TRUNCATE TABLE news_articles;
TRUNCATE TABLE medical_services;
TRUNCATE TABLE notifications;
TRUNCATE TABLE settings;
TRUNCATE TABLE audit_logs;
TRUNCATE TABLE invalidate_token;

SET FOREIGN_KEY_CHECKS = 1;

-- =========================
-- 1) MASTER DATA
-- =========================



-- 10 users total
-- U1-U5: doctor + admin accounts
-- U6-U10: patient accounts

-- user_role mappings (resolve role_id by role_name to avoid FK issues when IDs differ)
SELECT m.user_id, r.id
FROM (
	SELECT UUID_TO_BIN('11111111-1111-1111-1111-111111111111') AS user_id, 'ADMIN' AS role_name
	UNION ALL SELECT UUID_TO_BIN('11111111-1111-1111-1111-111111111111'), 'DOCTOR'
	UNION ALL SELECT UUID_TO_BIN('22222222-2222-2222-2222-222222222222'), 'ADMIN'
	UNION ALL SELECT UUID_TO_BIN('22222222-2222-2222-2222-222222222222'), 'DOCTOR'
	UNION ALL SELECT UUID_TO_BIN('33333333-3333-3333-3333-333333333333'), 'ADMIN'
	UNION ALL SELECT UUID_TO_BIN('33333333-3333-3333-3333-333333333333'), 'DOCTOR'
	UNION ALL SELECT UUID_TO_BIN('44444444-4444-4444-4444-444444444444'), 'ADMIN'
	UNION ALL SELECT UUID_TO_BIN('44444444-4444-4444-4444-444444444444'), 'DOCTOR'
	UNION ALL SELECT UUID_TO_BIN('55555555-5555-5555-5555-555555555555'), 'ADMIN'
	UNION ALL SELECT UUID_TO_BIN('55555555-5555-5555-5555-555555555555'), 'DOCTOR'
	UNION ALL SELECT UUID_TO_BIN('66666666-6666-6666-6666-666666666666'), 'PATIENT'
	UNION ALL SELECT UUID_TO_BIN('77777777-7777-7777-7777-777777777777'), 'PATIENT'
	UNION ALL SELECT UUID_TO_BIN('88888888-8888-8888-8888-888888888888'), 'PATIENT'
	UNION ALL SELECT UUID_TO_BIN('99999999-9999-9999-9999-999999999999'), 'PATIENT'
	UNION ALL SELECT UUID_TO_BIN('aaaaaaaa-aaaa-aaaa-aaaa-aaaaaaaaaaaa'), 'PATIENT'
) m
JOIN role r ON r.role_name = m.role_name;

