INSERT INTO news_articles (id, title, excerpt, content, image, category, author, author_image, published_at, views, featured) VALUES
(1, 'How to Control Blood Pressure at Home', 'Simple daily habits to maintain healthy blood pressure.', 'Detailed guide: low-salt diet, activity tracking, sleep regularity, and periodic measurement.', 'https://images.unsplash.com/photo-1512678080530-7760d81faba6', 'PREVENTIVE_CARE', 'Editorial Team', 'https://images.unsplash.com/photo-1544005313-94ddf0286df2', NOW() - INTERVAL 7 DAY, 1235, TRUE),
(2, 'When to Visit a Dermatologist', 'Recognize warning signs from common skin symptoms.', 'Includes practical checklist for acne, eczema, and suspected infections.', 'https://images.unsplash.com/photo-1559599101-f09722fb4948', 'DERMATOLOGY', 'Dr. Le Quang Quan', 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e', NOW() - INTERVAL 5 DAY, 844, FALSE),
(3, 'Child Fever: Home Care and Red Flags', 'What parents should monitor in first 24 hours.', 'Hydration, temperature logging, and clear thresholds for emergency care.', 'https://images.unsplash.com/photo-1503454537195-1dcabb73ffb9', 'PEDIATRICS', 'Dr. Pham Ngoc Lan', 'https://images.unsplash.com/photo-1494790108377-be9c29b29330', NOW() - INTERVAL 4 DAY, 980, TRUE),
(4, 'Sleep Hygiene for Busy Professionals', 'Evidence-based steps for better sleep quality.', 'Covers caffeine timing, screen light, and bedtime routine adjustments.', 'https://images.unsplash.com/photo-1455642305367-68834a9d39a0', 'NEUROLOGY', 'Dr. Vo Duc Phuc', 'https://images.unsplash.com/photo-1506794778202-cad84cf45f1d', NOW() - INTERVAL 2 DAY, 567, FALSE),
(5, 'Annual Health Checkup Checklist', 'What to prepare before a routine exam.', 'Medication list, recent symptoms, and previous test results to bring.', 'https://images.unsplash.com/photo-1579684385127-1ef15d508118', 'GENERAL_MEDICINE', 'Dr. Nguyen Van Minh', 'https://images.unsplash.com/photo-1508214751196-bcfd4ca60f91', NOW() - INTERVAL 1 DAY, 1502, TRUE);
